const topic = msg.topic;
const rawValue = msg.payload;
const value = Number(rawValue);
const now = new Date().toISOString();

const parts = topic.split("/");
const hardwarioNodeId = parts[1] || "unknown-device";

// Backend zatím zná toto zařízení:
const backendDeviceName = "mock-gateway-01";

let event = null;

// 1) TLAČÍTKO
if (topic.includes("/push-button/-/event-count")) {
  event = {
    deviceName: backendDeviceName,
    sensorKey: `${hardwarioNodeId}-button`,
    type: "tamper",
    value: value,
    message: `HARDWARIO button pressed: ${hardwarioNodeId}`,
    timestamp: now
  };
}

// 2) TEPLOTA
else if (topic.includes("/thermometer/") && topic.endsWith("/temperature")) {
  event = {
    deviceName: backendDeviceName,
    sensorKey: `${hardwarioNodeId}-thermometer`,
    type: "temperature",
    value: value,
    timestamp: now
  };
}

// 3) INFRARED / PIR POHYB
else if (
  topic.includes("/pir/") ||
  topic.includes("/infrared/") ||
  topic.includes("/motion-detector/")
) {
  event = {
    deviceName: backendDeviceName,
    sensorKey: `${hardwarioNodeId}-motion`,
    type: "tamper",
    value: isNaN(value) ? 1 : value,
    message: `Motion detected by infrared sensor: ${hardwarioNodeId}`,
    timestamp: now
  };
}

// 4) AKCELEROMETR
else if (
  topic.includes("/accelerometer/") ||
  topic.includes("/acceleration/")
) {
  const threshold = 1.2;

  if (isNaN(value) || value < threshold) {
    return null;
  }

  event = {
    deviceName: backendDeviceName,
    sensorKey: `${hardwarioNodeId}-accelerometer`,
    type: "tamper",
    value: value,
    message: `Acceleration threshold exceeded: ${hardwarioNodeId}`,
    timestamp: now
  };
}

// 5) BATERIE
else if (
  topic.includes("/battery/") ||
  topic.includes("/voltage")
) {
  event = {
    deviceName: backendDeviceName,
    sensorKey: `${hardwarioNodeId}-battery`,
    type: "battery",
    value: value,
    timestamp: now
  };
}

if (!event) {
  return null;
}

msg.payload = event;
return msg;

const baseUrl = String(
    env.get("CLOUD_BASE_URL") || env.get("CLOUD_API_BASE_URL") || ""
).replace(/\/+$/, "");

const token = env.get("DEVICE_TOKEN");

if (!baseUrl) {
    node.error("Missing CLOUD_BASE_URL", msg);
    return null;
}

if (!token) {
    node.error("Missing DEVICE_TOKEN", msg);
    return null;
}

msg.url = `${baseUrl}/api/event/create`;

msg.headers = {
    "Authorization": `Bearer ${token}`,
    "Content-Type": "application/json"
};

return msg;

const now = new Date().toISOString();

msg.payload = {
    deviceName: env.get("DEVICE_NAME") || "mock-gateway-01",
    sensorKey: "core-heartbeat",
    type: "heartbeat",
    value: 1,
    message: "Raspberry Pi gateway alive",
    timestamp: now
};

return msg;

const topic = msg.topic;
const parts = topic.split("/");

if (parts[0] === "node" && parts[1]) {
    const nodeId = parts[1];

    let lastSeen = flow.get("nodeLastSeen") || {};

    lastSeen[nodeId] = {
        nodeId,
        lastSeenAt: Date.now(),
        lastTopic: topic,
        lastPayload: msg.payload
    };

    flow.set("nodeLastSeen", lastSeen);
}

return msg;

const now = Date.now();
const nowIso = new Date().toISOString();

const offlineTimeoutMs = 2 * 60 * 1000;
const backendDeviceName = "mock-gateway-01";

const lastSeen = flow.get("nodeLastSeen") || {};
let knownStates = flow.get("nodeKnownStates") || {};

const events = [];

for (const nodeId of Object.keys(lastSeen)) {
    const ageMs = now - lastSeen[nodeId].lastSeenAt;
    const newState = ageMs > offlineTimeoutMs ? "offline" : "online";
    const oldState = knownStates[nodeId];

    if (oldState !== newState) {
        knownStates[nodeId] = newState;

        events.push({
            deviceName: backendDeviceName,
            sensorKey: `${nodeId}-status`,
            type: newState === "offline" ? "tamper" : "heartbeat",
            value: newState === "offline" ? 0 : 1,
            message: `HARDWARIO node ${newState}: ${nodeId}`,
            timestamp: nowIso
        });
    }
}

flow.set("nodeKnownStates", knownStates);

if (events.length === 0) {
    return null;
}

msg.payload = events;
return msg;

const topic = msg.topic;
const value = Number(msg.payload);

node.status({
    fill: "blue",
    shape: "dot",
    text: `${topic} = ${msg.payload}`
});

if (!topic.includes("/thermometer/")) {
    return null;
}

if (!topic.endsWith("/temperature")) {
    return null;
}

if (Number.isNaN(value)) {
    node.warn(`Invalid temperature value: ${msg.payload}`);
    return null;
}

msg.temperatureValue = value;
msg.hardwarioTopic = topic;

return msg;

const value = msg.temperatureValue;

let buffer = flow.get("temperatureBuffer") || [];

buffer.push({
    value,
    timestamp: Date.now(),
    topic: msg.hardwarioTopic
});

flow.set("temperatureBuffer", buffer);

node.status({
    fill: "green",
    shape: "dot",
    text: `${buffer.length} samples, last ${value}`
});

return null;

let buffer = flow.get("temperatureBuffer") || [];

if (buffer.length === 0) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: "no temperature samples"
    });
    return null;
}

const values = buffer
    .map(item => Number(item.value))
    .filter(value => !Number.isNaN(value));

if (values.length === 0) {
    flow.set("temperatureBuffer", []);
    node.warn("Temperature buffer contains no valid numeric values");
    return null;
}

const sum = values.reduce((acc, value) => acc + value, 0);
const avg = sum / values.length;

flow.set("temperatureBuffer", []);

msg.payload = {
    deviceName: "mock-gateway-01",
    sensorKey: "core-thermometer",
    type: "temperature",
    value: Number(avg.toFixed(2)),
    timestamp: new Date().toISOString()
};

node.status({
    fill: "blue",
    shape: "dot",
    text: `sent avg ${msg.payload.value} °C from ${values.length} samples`
});

return msg;
